import os
import json
import numpy as np
from flask import Flask, request, jsonify
from sklearn.ensemble import RandomForestClassifier
from sklearn.model_selection import train_test_split
from sklearn.metrics import accuracy_score
from collections import Counter
import hashlib
from datetime import datetime
import pickle

app = Flask(__name__)

# In-memory storage for labels and model
labels_storage = {}
model = None
label_history = {}

# Security controls
MAX_LABELS_PER_IMAGE = 100
MAX_LABELS_PER_ANNOTATOR = 1000
LABEL_HISTORY_LIMIT = 10000

def generate_label_id(image_id, annotator_id):
    """Generate unique label ID"""
    return hashlib.md5(f"{image_id}_{annotator_id}_{datetime.now().timestamp()}".encode()).hexdigest()

def is_valid_label(label):
    """Validate label format"""
    if not isinstance(label, str) or not label.strip():
        return False
    return True

def is_valid_image_id(image_id):
    """Validate image ID format"""
    if not isinstance(image_id, str) or not image_id.strip():
        return False
    return True

def is_valid_annotator_id(annotator_id):
    """Validate annotator ID format"""
    if not isinstance(annotator_id, str) or not annotator_id.strip():
        return False
    return True

def get_majority_vote(labels):
    """Get majority vote for labels"""
    if not labels:
        return None
    counter = Counter(labels)
    return counter.most_common(1)[0][0]

def store_label(image_id, annotator_id, label, confidence=1.0):
    """Store label with validation"""
    # Validate inputs
    if not is_valid_image_id(image_id):
        raise ValueError("Invalid image ID")
    if not is_valid_annotator_id(annotator_id):
        raise ValueError("Invalid annotator ID")
    if not is_valid_label(label):
        raise ValueError("Invalid label")
    
    # Check limits
    if image_id in labels_storage and len(labels_storage[image_id]) >= MAX_LABELS_PER_IMAGE:
        raise ValueError("Maximum labels per image reached")
    
    if annotator_id in label_history and len(label_history[annotator_id]) >= MAX_LABELS_PER_ANNOTATOR:
        raise ValueError("Maximum labels per annotator reached")
    
    # Generate label ID
    label_id = generate_label_id(image_id, annotator_id)
    
    # Store label
    if image_id not in labels_storage:
        labels_storage[image_id] = []
    
    label_entry = {
        'label_id': label_id,
        'image_id': image_id,
        'annotator_id': annotator_id,
        'label': label,
        'confidence': float(confidence),
        'timestamp': datetime.now().isoformat()
    }
    
    labels_storage[image_id].append(label_entry)
    
    # Update label history
    if annotator_id not in label_history:
        label_history[annotator_id] = []
    
    label_history[annotator_id].append(label_entry)
    
    # Limit history
    if len(label_history[annotator_id]) > LABEL_HISTORY_LIMIT:
        label_history[annotator_id] = label_history[annotator_id][-LABEL_HISTORY_LIMIT:]
    
    return label_id

def aggregate_labels(image_id):
    """Aggregate labels using majority voting"""
    if image_id not in labels_storage:
        return None
    
    labels = [entry['label'] for entry in labels_storage[image_id]]
    return get_majority_vote(labels)

def train_model_on_labels():
    """Train model on aggregated labels"""
    global model
    
    if not labels_storage:
        return False
    
    # Prepare training data
    X = []
    y = []
    
    for image_id, entries in labels_storage.items():
        # Get aggregated label
        aggregated_label = aggregate_labels(image_id)
        if aggregated_label is None:
            continue
            
        # For demo purposes, we'll use a simple feature representation
        # In practice, this would be image features
        features = [hash(image_id) % 1000, len(entries), len(image_id)]
        X.append(features)
        y.append(aggregated_label)
    
    if len(X) == 0:
        return False
    
    # Convert to numpy arrays
    X = np.array(X)
    y = np.array(y)
    
    # Train model
    model = RandomForestClassifier(n_estimators=10, random_state=42)
    model.fit(X, y)
    
    return True

@app.route('/label', methods=['POST'])
def submit_label():
    """Submit a label for an image"""
    try:
        data = request.get_json()
        
        image_id = data.get('image_id')
        annotator_id = data.get('annotator_id')
        label = data.get('label')
        confidence = data.get('confidence', 1.0)
        
        if not all([image_id, annotator_id, label]):
            return jsonify({'error': 'Missing required fields'}), 400
        
        label_id = store_label(image_id, annotator_id, label, confidence)
        
        # Retrain model after each label submission
        train_model_on_labels()
        
        return jsonify({
            'success': True,
            'label_id': label_id,
            'image_id': image_id
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 400

@app.route('/labels/<image_id>', methods=['GET'])
def get_labels(image_id):
    """Get all labels for an image"""
    try:
        if image_id not in labels_storage:
            return jsonify({'labels': []})
        
        return jsonify({
            'image_id': image_id,
            'labels': labels_storage[image_id]
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 400

@app.route('/aggregate/<image_id>', methods=['GET'])
def get_aggregated_label(image_id):
    """Get aggregated label for an image"""
    try:
        aggregated = aggregate_labels(image_id)
        return jsonify({
            'image_id': image_id,
            'aggregated_label': aggregated
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 400

@app.route('/model/predict', methods=['POST'])
def predict():
    """Predict using trained model"""
    try:
        global model
        if model is None:
            return jsonify({'error': 'Model not trained'}), 400
        
        data = request.get_json()
        image_id = data.get('image_id')
        
        if not image_id:
            return jsonify({'error': 'Missing image_id'}), 400
        
        # Create features for prediction
        features = [hash(image_id) % 1000, len(labels_storage.get(image_id, [])), len(image_id)]
        
        prediction = model.predict([features])[0]
        probability = model.predict_proba([features])[0].max()
        
        return jsonify({
            'image_id': image_id,
            'prediction': prediction,
            'confidence': float(probability)
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 400

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)